mapper.update:
UPDATE grades SET
score = #{score},
grade_level = #{gradeLevel},
comment = #{comment}
WHERE grade_id = #{gradeId}

mapper.select:
SELECT g.* FROM grades g
JOIN course_enrollments ce ON g.enrollment_id = ce.enrollment_id
WHERE ce.schedule_id = #{scheduleId}

    AND g.grade_level = #{gradeLevel}

LIMIT #{limit} OFFSET #{offset}

SELECT g.* FROM grades g
JOIN course_enrollments ce ON g.enrollment_id = ce.enrollment_id
JOIN course_schedules cs ON ce.schedule_id = cs.schedule_id
WHERE ce.student_id = #{studentId}

    AND cs.semester = #{semester}


    AND cs.year = #{year}

LIMIT #{limit} OFFSET #{offset}

SELECT g.grade_id AS gradeId, g.score, g.grade_level AS gradeLevel, g.comment, g.created_at AS createdAt, s.student_id AS studentId, s.name AS studentName, s.student_number AS studentNumber, c.course_name AS courseName, c.course_code AS courseCode, c.credit, t.name AS teacherName, cs.semester, cs.year FROM grades g JOIN course_enrollments ce ON g.enrollment_id = ce.enrollment_id JOIN students s ON ce.student_id = s.student_id JOIN course_schedules cs ON ce.schedule_id = cs.schedule_id JOIN courses c ON cs.course_id = c.course_id JOIN teachers t ON cs.teacher_id = t.teacher_id WHERE ce.schedule_id = #{scheduleId}
AND g.grade_level = #{gradeLevel}
ORDER BY s.student_number LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM grades g
JOIN course_enrollments ce ON g.enrollment_id = ce.enrollment_id
WHERE ce.schedule_id = #{scheduleId}

    AND g.grade_level = #{gradeLevel}

SELECT g.grade_id AS gradeId, g.score, g.grade_level AS gradeLevel, g.comment, g.created_at AS createdAt, c.course_name AS courseName, c.course_code AS courseCode, c.credit, t.name AS teacherName, cs.semester, cs.year FROM grades g JOIN course_enrollments ce ON g.enrollment_id = ce.enrollment_id JOIN course_schedules cs ON ce.schedule_id = cs.schedule_id JOIN courses c ON cs.course_id = c.course_id JOIN teachers t ON cs.teacher_id = t.teacher_id WHERE ce.student_id = #{studentId}
AND cs.semester = #{semester}
AND cs.year = #{year}
ORDER BY cs.year DESC, cs.semester DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM grades g
JOIN course_enrollments ce ON g.enrollment_id = ce.enrollment_id
JOIN course_schedules cs ON ce.schedule_id = cs.schedule_id
WHERE ce.student_id = #{studentId}

    AND cs.semester = #{semester}


    AND cs.year = #{year}
